import{kn as e}from"./chunk-IjxM6APl.js";var t=e(),n={publishing_date:`2025-04-21`,title:`A decentral support button`,category:`blockchain`,secondaryCategory:`webdev`,description:`I build a decentralized support button using smart contracts for direct content monetization. Learn how blockchain enables transparent micro-payments without platform intermediaries.`};function r(e){let n={a:`a`,code:`code`,h2:`h2`,h3:`h3`,li:`li`,ol:`ol`,p:`p`,ul:`ul`,...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsxs)(n.p,{children:[`I recently came across the `,(0,t.jsx)(n.code,{children:`mirror`}),` platfrom and was really impressed by the possibilities of such a dentralized `,(0,t.jsx)(n.a,{href:`4`,children:`social platform`}),`. What intrigued me most is that it might give content creators a very simple and direct way to get paid for the content. But after some more digging I must admit that it is not clear to me if `,(0,t.jsx)(n.a,{href:`https://mirror.xyz/`,children:`mirror.xyz`}),` is still really actively maintained. So I decided to give it a try and see if I might be able to build something similar. As you can see on the top right of this site I succeeded and will explain how I did it. I am not sure yet how long this post will be, so buckle up.`]}),`
`,(0,t.jsx)(n.h2,{children:`The goal`}),`
`,(0,t.jsx)(n.p,{children:`I wanted to have a simple like / support button. Its functionality is quite straightforward:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`As the user clicks on the button, he commits to support the content with a small amount of money.`}),`
`,(0,t.jsx)(n.li,{children:`The support is done via a transaction on the blckchain.`}),`
`,(0,t.jsx)(n.li,{children:`The smart contract keeps track of the number of likes for each site.`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`For me this is interesting for a few reasons:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`It is a really simple smart contract. So it allows me to learn the basics of smart contracts in a very simple way.`}),`
`,(0,t.jsx)(n.li,{children:`It sets up a simple way to support the content that I create on this website.`}),`
`]}),`
`,(0,t.jsx)(n.h2,{children:`How to use the support button`}),`
`,(0,t.jsxs)(n.p,{children:[`To use the button you need to have a wallet that is connected to the Ethereum network. I used `,(0,t.jsx)(n.a,{href:`https://metamask.io/`,children:`MetaMask`}),` for this.`]}),`
`,(0,t.jsxs)(n.p,{children:[`In the next step, you need to make sure that you have sufficent ETH on the `,(0,t.jsx)(n.a,{href:`https://www.optimism.io`,children:`optimism chain`}),`. If you don't have any ETH on the optimism chain, you can use the `,(0,t.jsx)(n.a,{href:`https://app.optimism.io/bridge`,children:`optimism bridge`}),` to transfer some ETH from the Ethereum mainnet to the optimism chain.`]}),`
`,(0,t.jsx)(n.p,{children:`Now, you are all set up to use the support button that you can find on the top right of this page. When you click it, a popup will open that allows you to send ETH to the smart contract. The amount of ETH is set to 0.002 ETH (rougly 50 cents). Once you confirm the transation, the smart contract will be called and the amount of ETH will be sent to the smart contract. The smart contract will then keep track of the number of likes for this specific URL and the number of supporters will be incremented. Thanks for your support!`}),`
`,(0,t.jsx)(n.p,{children:`Now that you know how to use the button, I will explain how I set everything up.`}),`
`,(0,t.jsx)(n.h2,{children:`Setting up the smart contract`}),`
`,(0,t.jsx)(n.p,{children:`In a first step, I had to decide how my smart contract should look like and then also set everything up to deploy it.`}),`
`,(0,t.jsx)(n.h3,{children:`The smart contract`}),`
`,(0,t.jsxs)(n.p,{children:[`I decided for a really simple approach based on `,(0,t.jsx)(n.a,{href:`https://soliditylang.org/`,children:`solidity`}),`. The `,(0,t.jsx)(n.code,{children:`Support`}),` smart contract main hasly the `,(0,t.jsx)(n.code,{children:`donate`}),` function, which takes a URL as input and allows users to send ETH as a form of appreciation. Once the donation is called, ETH is transferred to the contract owner and the count of `,(0,t.jsx)(n.code,{children:`urlLikes`}),` is incremented.`]}),`
`,(0,t.jsxs)(n.p,{children:[`The contract also includes a `,(0,t.jsx)(n.code,{children:`getLikesForUrl`}),` function, which allows anyone to check the number of likes for a specific URL. The contract is designed to be secure and efficient, utilizing OpenZeppelin's libraries for access control and reentrancy protection. One of the neat things of the blockchain is that you can the see fully deployed and verified code `,(0,t.jsx)(n.a,{href:`https://optimistic.etherscan.io/address/0x314b07fbd33a7343479e99e6682d5ee1da7f17c1#code#F1#L1`,children:`here`}),`.`]}),`
`,(0,t.jsx)(n.p,{children:`As I designed the contract, I actually wondered if I should use other approaches like NFTs or ERC20 tokens. But in the end there is no need for that at this stage and any of those increasing complexities may increase the risk of bugs and the gas fees.`}),`
`,(0,t.jsx)(n.h3,{children:`Deploying and testing the smart contract`}),`
`,(0,t.jsxs)(n.p,{children:[`As this was my first smart contract, I actually had to learn all the basics. It would seem that you have two major frameworks nowadays: `,(0,t.jsx)(n.a,{href:`https://book.getfoundry.sh/`,children:`Foundry`}),` and `,(0,t.jsx)(n.a,{href:`https://hardhat.org/`,children:`Hardhat`}),`. Hardhat seemed to fulfill all my requirements and well integrated into the usual javascript workflows. To get started, I really like the documentation for the `,(0,t.jsx)(n.a,{href:`https://hardhat.org/hardhat-runner/docs/guides/compile-contracts`,children:`Hardhat Runner`}),` here. In summary, the steps are:`]}),`
`,(0,t.jsxs)(n.ol,{children:[`
`,(0,t.jsx)(n.li,{children:`Install hardhat and the dependencies`}),`
`,(0,t.jsxs)(n.li,{children:[`Compile the contracts `,(0,t.jsx)(n.code,{children:`npx hardhat compile`}),`.`]}),`
`,(0,t.jsxs)(n.li,{children:[`Write the tests for the contracts. I used `,(0,t.jsx)(n.a,{href:`https://www.chaijs.com/`,children:`chai`}),` and `,(0,t.jsx)(n.a,{href:`https://hardhat.org/hardhat-runner/docs/advanced/using-viem`,children:`viem`}),` for this.`]}),`
`]}),`
`,(0,t.jsxs)(n.p,{children:[`Now we are ready to deploy and test the contract. In the test environment this is quite straightforward as described `,(0,t.jsx)(n.a,{href:`https://hardhat.org/hardhat-runner/docs/guides/deploying`,children:`here`}),`. But as you would like to deploy the contract to a real network, you need to set up a few things as described `,(0,t.jsx)(n.a,{href:`https://hardhat.org/hardhat-runner/docs/guides/verifying`,children:`here`}),`. First, you need to create an account on `,(0,t.jsx)(n.a,{href:`https://www.alchemy.com/`,children:`Alchemy`}),` and get an API key. Then we can once again deploy the contract to the network of my choice, which was Optimism.`]}),`
`,(0,t.jsxs)(n.p,{children:[`Finally, we need to verify the contract on the blockchain. This is important as it allows others to see the code and verify that it is working as expected. Here again we need to set up a few things. First, you need to create an account on `,(0,t.jsx)(n.a,{href:`https://etherscan.io/`,children:`Etherscan`}),` and get an API key. Then, you need to set up the `,(0,t.jsx)(n.code,{children:`ETHERSCAN_API_KEY`}),` environment variable with your API key.`]}),`
`,(0,t.jsx)(n.h3,{children:`The Optimism chain`}),`
`,(0,t.jsx)(n.p,{children:`One of the crucial points for the support button was that it must not be too costly to use. On the Ethereum mainnet, I have frequently encountered gas fees of 20-50 USD. This would have been prohibitive for a simple like button.`}),`
`,(0,t.jsx)(n.p,{children:`Every blockchain transaction requires computational resources that must be paid for with "gas fees." These fees represent the cost of having your transaction processed and validated by the network:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`On Ethereum's mainnet, high demand for block space drives fees to levels that make micro-transactions impractical`}),`
`,(0,t.jsxs)(n.li,{children:[`When gas costs `,(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`20-50 per transaction, sending a `}),`0.50 support donation becomes economically absurd`]}),`
`,(0,t.jsx)(n.li,{children:`Layer 2 solutions like Optimism process transactions in batches and post the cryptographic proof to Ethereum, distributing that mainnet gas cost across many transactions.`}),`
`]}),`
`,(0,t.jsxs)(n.p,{children:[`Therefore, I decided to investigate layer-2 alternatives, which promise much lower fees. As I investigated the major alternatives, I came across `,(0,t.jsx)(n.a,{href:`https://www.base.org/`,children:`Base`}),`, `,(0,t.jsx)(n.a,{href:`https://arbitrum.io/`,children:`Arbitrum`}),`, `,(0,t.jsx)(n.a,{href:`https://www.optimism.io/`,children:`Optimism`}),` and `,(0,t.jsx)(n.a,{href:`https://linea.build/`,children:`Linea`}),`. All of them seemed fairly mature with slightly different focuses. Base is closely aligned with Coinbase, which makes it a bit less attractive for me. Linea seemed to be still quite new and not as widely adopted. Optimism on the other hand has some nice documententation, a strong community focus and a lot of projects already running on it. So I decided to go with Optimism.`]}),`
`,(0,t.jsxs)(n.p,{children:[`You can see all the details for the deployed contract and activity on `,(0,t.jsx)(n.a,{href:`https://optimistic.etherscan.io/address/0x314b07fbd33a7343479e99e6682d5ee1da7f17c1`,children:`Optimism Etherscan`}),`.`]}),`
`,(0,t.jsx)(n.h2,{children:`The frontend`}),`
`,(0,t.jsxs)(n.p,{children:[`After I had the smart contract up and running, I needed to integrate it into the website. I decided to integrate it via `,(0,t.jsx)(n.a,{href:`https://wagmi.sh/`,children:`wagmi`}),`, which is a library that makes it easy to interact with Ethereum from a react app. It provides a simple API for connecting to wallets, sending transactions, and reading data from the blockchain. It is also built around `,(0,t.jsx)(n.a,{href:`https://viem.sh/`,children:`viem`}),`, which is a library for interacting with Ethereum in a type-safe way. This makes it easy to work with the blockchain and ensures that the code is safe and secure.`]}),`
`,(0,t.jsx)(n.p,{children:`The integration itself, involved two parts:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`the connection to the wallet.`}),`
`,(0,t.jsx)(n.li,{children:`the button itself.`}),`
`]}),`
`,(0,t.jsx)(n.h3,{children:`The wallet connection`}),`
`,(0,t.jsxs)(n.p,{children:[`To set up the wallet, I followed quite closely the `,(0,t.jsx)(n.a,{href:`https://wagmi.sh/react/getting-started`,children:`wagmi documentation`}),`. However, I am using `,(0,t.jsx)(n.code,{children:`vike`}),` and there is no `,(0,t.jsx)(n.code,{children:`App.tsx`}),`. So the integration is a bit different. I was able to activate `,(0,t.jsx)(n.code,{children:`tanstack-query`}),` with the `,(0,t.jsx)(n.a,{href:`https://vike.dev/tanstack-query`,children:`official plugin`}),`. To wrap Wagmi itself, I hooked into the `,(0,t.jsx)(n.code,{children:`LayoutDefault.tsx`}),` component, which worked out quite nicely. For the rest I could simply follow the very simple and straight forward guide `,(0,t.jsx)(n.a,{href:`https://wagmi.sh/react/guides/connect-wallet`,children:`here`}),`. I had a quick look into the different kits, but wanted to learn things for myself at this stage. If I ever decide to use one of the kits, I will likely try out `,(0,t.jsx)(n.a,{href:`https://appkit.dev/`,children:`AppKit`}),` first.`]}),`
`,(0,t.jsx)(n.h3,{children:`The support button`}),`
`,(0,t.jsxs)(n.p,{children:[`Now that the wallet was set up, I could directly integrate the support button. This was also surprisingly straight forward as I could simply follow the documentation on how to `,(0,t.jsx)(n.a,{href:`https://wagmi.sh/react/guides/write-to-contract`,children:`write`}),` and `,(0,t.jsx)(n.a,{href:`https://wagmi.sh/react/guides/read-from-contract`,children:`read`}),` small contracts. To get the number of supports, I simply call the `,(0,t.jsx)(n.code,{children:`getLikesForUrl`}),` function of the smart contract. To support the content, I call the `,(0,t.jsx)(n.code,{children:`donate`}),` function of the smart contract. That's it. As every developer in the world, I spent too much time one the styling of the button, but otherwise it was simply an enjoyable experience.`]}),`
`,(0,t.jsx)(n.h2,{children:`My main learnings`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`Fees on L2 chains are really low now. A transfer of 50 cents sometimes costs less than 1 cent in gas fees. So this problem is really pretty much solved for now and L2s are really usable.`}),`
`,(0,t.jsx)(n.li,{children:`The development experience is really quite nice. Backend and frontend are nicely separated etc.`}),`
`,(0,t.jsx)(n.li,{children:`The biggest question for me will be how the whole transfer to L2 chains will work out in the long term.`}),`
`,(0,t.jsx)(n.li,{children:`I will continue to play with similiar applications as soon as I think about some kind of transfers.`}),`
`]}),`
`,(0,t.jsx)(n.h2,{children:`A small look into the future`}),`
`,(0,t.jsx)(n.p,{children:`I learned a few things that I would likely change in the future. I have mainly two things in mind.`}),`
`,(0,t.jsxs)(n.ol,{children:[`
`,(0,t.jsxs)(n.li,{children:[`First, I would like to make sure that the contract is `,(0,t.jsx)(n.a,{href:`https://docs.openzeppelin.com/upgrades-plugins/writing-upgradeable`,children:`upgradable`}),`. While it would make the initial deployment process more complex, it would make the entire system much easier to maintain in the long run.`]}),`
`,(0,t.jsx)(n.li,{children:`Second, I would most likely make it possible to select the adress of the recipient. This would also allow others to use the same contract and make the whole thing a bit more generic.`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`So I hope that you enjoyed the post. Comments as usual below. And any support through the support button is highly appreciated.`})]})}function i(e={}){let{wrapper:n}=e.components||{};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(r,{...e})}):r(e)}export{i as default,n as frontmatter};